def solve(transactions):
    from collections import defaultdict
    net = defaultdict(int)
    for u, v, amt in transactions:
        net[u] -= amt
        net[v] += amt
    debts = [x for x in net.values() if x != 0]
    def dfs(idx):
        while idx < len(debts) and debts[idx] == 0:
            idx += 1
        if idx == len(debts): return 0
        res = float('inf')
        for i in range(idx + 1, len(debts)):
            if debts[i] * debts[idx] < 0:
                debts[i] += debts[idx]
                res = min(res, 1 + dfs(idx + 1))
                debts[i] -= debts[idx]
        return res
    return str(dfs(0))

